using Microsoft.EntityFrameworkCore;
using Microsoft.EntityFrameworkCore.ValueGeneration;
using Microsoft.EntityFrameworkCore.ChangeTracking;

class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();

    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(b =>
        {
            b.ToContainer("Products");

            // BREAKING CHANGE 1 — Discriminator property renamed "$type" (was "Discriminator").
            // Existing 500K docs store "Discriminator"; raw SQL references c.Discriminator.
            // Fix: keep the old property name explicitly.
            b.HasDiscriminator<string>("Discriminator").HasValue("Product");

            // BREAKING CHANGE 2 — id values no longer prefixed with discriminator.
            // EF Core 8 wrote id = "Product|123"; EF Core 9 writes id = "123".
            // Existing docs won't be found without this fix.
            // Fix: shadow property with a value generator that preserves the legacy format.
            b.Property<string>("__id")
                .ToJsonProperty("id")
                .HasValueGenerator<LegacyCosmosIdGenerator>();

            // BREAKING CHANGE 3 — HasIndex() now throws for the Cosmos provider.
            // Cosmos manages indexing via its own indexing policy, not EF.
            // Fix: removed the HasIndex(p => p.Sku) call.
        });
    }
}

/// <summary>
/// Generates Cosmos id values in the legacy "Product|{key}" format
/// so EF Core 9 can read documents written by EF Core 8.
/// </summary>
class LegacyCosmosIdGenerator : ValueGenerator<string>
{
    public override bool GeneratesTemporaryValues => false;

    public override string Next(EntityEntry entry)
    {
        var discriminator = entry.Metadata.GetDiscriminatorValue();
        var key = entry.Property("Id").CurrentValue;
        return $"{discriminator}|{key}";
    }
}

class Product
{
    public int Id { get; set; }
    public string Sku { get; set; }
}

